/**
 * Represents a basic send call response
 */
export interface Response {
    /**
     * visitorId is the main visitor identifier that you should use.
     */
    visitorId: string;
    /**
     * Tag is an object of metadata, associated with current send request
     */
    tag: object;
    /**
     * Error that may have occurred
     */
    error?: string;
}
/**
 * Represents an extended send call response.
 * Only available when `callbackData: true` send option was used.
 */
export interface ExtendedResponse extends Response {
    /**
     * @deprecated Agent doesn't detect bots
     */
    botProbability: number;
    /**
     * Browser name, e.g. "Safari" or "Chrome"
     */
    browserName: string;
    /**
     * Browser version, e.g. "78.0.3904"
     */
    browserVersion: string;
    /**
     * Device, e.g. "Samsung SM-J330F".
     * For desktop/laptop devices, the value will be "Other"
     */
    device: string;
    /**
     * IP address. Only IPv4 are returned. Example: 191.14.35.17
     */
    ip: string;
    /**
     * IP address location. Can be empty for anonymous proxies
     */
    ipLocation: {
        /**
         * IP address location detection radius. Smaller values (<50mi) are business/residential,
         * medium values (50 < x < 500) are cellular towers (usually),
         * larger values (>= 500) are cloud IPs or proxies, VPNs.
         * Can be missing, in case of Tor/proxies.
         */
        accuracyRadius?: number;
        /**
         * Latitude, e.g. -19.8975.
         * Can be missing, in case of Tor/proxies.
         */
        latitude?: number;
        /**
         * Longitude, e.g. -43.9625.
         * Can be missing, in case of Tor/proxies.
         */
        longitude?: number;
        /**
         * Timezone of the IP address location, e.g. America/Chicago
         */
        timezone?: string;
        /**
         * Postal code, when available
         */
        postalCode?: string;
        /**
         * City, when available
         */
        city?: {
            name: string;
        };
        /**
         * Administrative subdivisions array (for example states|provinces -> counties|parishes).
         * Can be empty or missing. When not empty, can contain only top-level administrative units within a country, e.g. a state.
         */
        subdivisions?: [
            {
                isoCode: string;
                name: string;
            }
        ];
        /**
         * Country, when available. Will be missing for Tor/anonymous proxies.
         */
        country?: {
            code: string;
            name: string;
        };
        /**
         * Continent, when available. Will be missing for Tor/anonymous proxies.
         */
        continent?: {
            code: string;
            name: string;
        };
        /**
         * This response is only available when used with "full" IP resolution.
         */
        organization?: {
            name: string;
            domain: string;
            isp: string;
            legalName: string;
        };
    };
    /**
     * OS name, e.g. "Mac OS X" or "Windows" or "Android"
     */
    os: string;
    /**
     * OS version, e.g. "10.13.6"
     */
    osVersion: string;
}
